#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 50000
#define INF 1000000000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T, N, i, j, k, x, y, max, max_index;
    int *P, *A;
    int **G;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        P = (int*)malloc(N * sizeof(int));
        A = (int*)malloc(N * sizeof(int));
        G = (int**)malloc(N * sizeof(int*));
        for (i = 0; i < N; i++) {
            scanf("%d", &P[i]);
            G[i] = (int*)malloc(2 * sizeof(int));
            G[i][0] = G[i][1] = 0;
        }
        for (i = 0; i < N - 1; i++) {
            scanf("%d %d", &x, &y);
            G[x - 1][G[x - 1][0]++] = y - 1;
            G[y - 1][G[y - 1][0]++] = x - 1;
        }
        for (i = 0; i < N; i++) {
            max = -INF;
            max_index = 0;
            for (j = 0; j < N; j++) {
                if (i != j) {
                    int *visited = (int*)malloc(N * sizeof(int));
                    for (k = 0; k < N; k++) {
                        visited[k] = 0;
                    }
                    int queue[N], front = 0, rear = 0;
                    queue[rear++] = i;
                    visited[i] = 1;
                    while (front < rear) {
                        x = queue[front++];
                        for (k = 0; k < G[x][0]; k++) {
                            if (!visited[G[x][k]]) {
                                queue[rear++] = G[x][k];
                                visited[G[x][k]] = 1;
                            }
                        }
                    }
                    if (!visited[j] && P[j] > max) {
                        max = P[j];
                        max_index = j + 1;
                    }
                    free(visited);
                }
            }
            A[i] = max_index;
        }
        for (i = 0; i < N; i++) {
            printf("%d ", A[i]);
        }
        printf("\n");
        free(P);
        free(A);
        for (i = 0; i < N; i++) {
            free(G[i]);
        }
        free(G);
    }
    return 0;
}

