using namespace std;

int main() {
    int T, N, i, j, k, x, y, max, max_index;
    cin >> T;
    while (T--) {
        cin >> N;
        vector<int> P(N), A(N);
        vector<vector<int>> G(N);
        for (i = 0; i < N; i++) {
            cin >> P[i];
        }
        for (i = 0; i < N - 1; i++) {
            cin >> x >> y;
            G[x - 1].push_back(y - 1);
            G[y - 1].push_back(x - 1);
        }
        for (i = 0; i < N; i++) {
            max = -1000000000;
            max_index = 0;
            for (j = 0; j < N; j++) {
                if (i != j) {
                    vector<int> visited(N, 0);
                    queue<int> q;
                    q.push(i);
                    visited[i] = 1;
                    while (!q.empty()) {
                        x = q.front();
                        q.pop();
                        for (k = 0; k < G[x].size(); k++) {
                            if (!visited[G[x][k]]) {
                                q.push(G[x][k]);
                                visited[G[x][k]] = 1;
                            }
                        }
                    }
                    if (!visited[j] && P[j] > max) {
                        max = P[j];
                        max_index = j + 1;
                    }
                }
            }
            A[i] = max_index;
        }
        for (i = 0; i < N; i++) {
            cout << A[i] << " ";
        }
        cout << endl;
    }
    return 0;
}

