import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] P = new int[N];
            int[] A = new int[N];
            int[][] G = new int[N][N];
            for (int i = 0; i < N; i++) {
                P[i] = sc.nextInt();
            }
            for (int i = 0; i < N - 1; i++) {
                int x = sc.nextInt() - 1;
                int y = sc.nextInt() - 1;
                G[x][y] = G[y][x] = 1;
            }
            for (int i = 0; i < N; i++) {
                int max = -1000000000;
                int max_index = 0;
                for (int j = 0; j < N; j++) {
                    if (i != j) {
                        boolean[] visited = new boolean[N];
                        Queue<Integer> q = new LinkedList<>();
                        q.add(i);
                        visited[i] = true;
                        while (!q.isEmpty()) {
                            int x = q.poll();
                            for (int k = 0; k < N; k++) {
                                if (G[x][k] == 1 && !visited[k]) {
                                    q.add(k);
                                    visited[k] = true;
                                }
                            }
                        }
                        if (!visited[j] && P[j] > max) {
                            max = P[j];
                            max_index = j + 1;
                        }
                    }
                }
                A[i] = max_index;
            }
            for (int i = 0; i < N; i++) {
                System.out.print(A[i] + " ");
            }
            System.out.println();
        }
    }
}

