const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(input[idx++]);
}

function nextIntArray() {
    return input[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let P = nextIntArray();
    let G = Array(N).fill(0).map(() => []);
    for (let i = 0; i < N - 1; i++) {
        let [x, y] = nextIntArray();
        G[x - 1].push(y - 1);
        G[y - 1].push(x - 1);
    }
    let A = Array(N).fill(0);
    for (let i = 0; i < N; i++) {
        let max = -1000000000;
        let max_index = 0;
        for (let j = 0; j < N; j++) {
            if (i != j) {
                let visited = Array(N).fill(false);
                let q = [i];
                visited[i] = true;
                while (q.length > 0) {
                    let x = q.shift();
                    for (let k of G[x]) {
                        if (!visited[k]) {
                            q.push(k);
                            visited[k] = true;
                        }
                    }
                }
                if (!visited[j] && P[j] > max) {
                    max = P[j];
                    max_index = j + 1;
                }
            }
        }
        A[i] = max_index;
    }
    console.log(A.join(' '));
}

